VALUES
('std_adv_001', 'ADVOCIS', 'CONSTITUTIONAL', 'US', 'U.S. Const. amend. XIV, § 1', '14th Amendment — Due Process', 'Fourteenth Amendment Due Process Clause', 'No state shall deprive any person of life, liberty, or property without due process of law.', '["Procedural due process: notice and opportunity to be heard","Substantive due process: fundamental rights protection","Applies to all state actors including courts, agencies, police"]', '[{"section":"Due Process Clause","description":"State deprivation of life, liberty, or property requires due process"},{"section":"Equal Protection Clause","description":"No denial of equal protection of the laws"}]', '["court_order","agency_action","police_action","custody_order"]', '["constitutional-and-civil-rights-audit"]', 'Federal Courts / DOJ', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_002', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', '42 USC § 1983', '§ 1983', 'Civil Action for Deprivation of Rights Under Color of Law', 'Every person who, under color of state law, deprives another of constitutional rights is liable in an action at law.', '["State actor requirement (color of law)","Deprivation of federal constitutional or statutory right","No qualified immunity for clearly established violations","Municipal liability under Monell for policy or custom"]', '[{"section":"1983","description":"Individual liability for constitutional violations"},{"section":"Monell","description":"Municipal liability for policy/custom/failure to train"}]', '["federal_complaint","1983_complaint","civil_rights_complaint"]', '["constitutional-and-civil-rights-audit"]', 'Federal District Courts', 1, 1, datetime('now'), datetime('now'));

