VALUES
('std_adv_003', 'ADVOCIS', 'CONSTITUTIONAL', 'US', 'U.S. Const. amend. IV', '4th Amendment', 'Fourth Amendment — Unreasonable Search and Seizure', 'Protection against unreasonable searches and seizures; warrants require probable cause.', '["Warrant requirement with exceptions","Probable cause standard","Exclusionary rule for illegally obtained evidence","Applies to persons, houses, papers, and effects"]', '[{"section":"Warrant Clause","description":"Warrants require probable cause and particularity"},{"section":"Reasonableness Clause","description":"All searches and seizures must be reasonable"}]', '["search_warrant","arrest_report","police_report","motion_to_suppress"]', '["constitutional-and-civil-rights-audit","police-report-data-cross-reference"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

