('std_adv_005', 'ADVOCIS', 'CONSTITUTIONAL', 'CA', 'Cal. Const. art. I, § 28', 'Marsy''s Law', 'California Crime Victims'' Bill of Rights (Marsy''s Law)', 'Constitutional rights of crime victims including notification, participation, restitution, and protection.', '["Right to be heard at any proceeding involving release, plea, sentencing, or parole","Right to notification of all proceedings","Right to restitution from convicted defendant","Right to refuse discovery requests from the defendant","Right to be treated with fairness, respect, and dignity"]', '[{"section":"28(a)","description":"Purpose and findings"},{"section":"28(b)","description":"Enumerated victim rights (17 rights)"},{"section":"28(c)","description":"Standing to assert rights"},{"section":"28(e)","description":"Enforcement mechanisms"}]', '["victim_notification","restitution_order","protective_order","parole_hearing"]', '["marsys-law-victim-rights-audit"]', 'California Victim Compensation Board / District Attorney', 1, 1, datetime('now'), datetime('now'));

