VALUES
('std_adv_006', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code §§ 679-679.026', 'PC §§ 679+', 'Victim Rights Implementation Statutes', 'Implementing statutes for Marsy''s Law providing specific procedural requirements for victim notification and participation.', '["Law enforcement must provide Marsy''s Law card at scene","Prosecutors must notify victims of all proceedings","CLETS entries must include victim notification flags","Victims may appear at any hearing"]', '[{"section":"679.02","description":"Rights of victims and witnesses"},{"section":"679.026","description":"Notification requirements"}]', '["police_report","victim_notification","CLETS_entry","court_notice"]', '["marsys-law-victim-rights-audit"]', 'California DOJ / District Attorney', 1, 1, datetime('now'), datetime('now'));

