VALUES
('std_adv_013', 'ADVOCIS', 'CASE_LAW', 'CA', 'Marriage of LaMusga (2004) 32 Cal.4th 1072', 'LaMusga', 'Move-Away Cases — Burden of Proof', 'In custody move-away cases, the non-custodial parent bears the initial burden of showing the move would cause detriment to the child.', '["Custodial parent has presumptive right to relocate","Non-custodial parent must show detriment","Court must consider all best interest factors","Changed circumstances standard applies"]', '[{"section":"Holding","description":"Burden on non-custodial parent to show detriment from move"},{"section":"Standard","description":"Changed circumstances plus best interest analysis"}]', '["move_away_motion","custody_modification","declaration"]', '["california-family-law-expansion-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));

