VALUES
('std_adv_014', 'ADVOCIS', 'CASE_LAW', 'CA', 'Marriage of Burgess (1996) 13 Cal.4th 25', 'Burgess', 'Custodial Parent Relocation Rights', 'Custodial parent has a presumptive right to change the residence of the child subject to the power of the court to restrain a removal that would prejudice the rights or welfare of the child.', '["Presumptive right to relocate with child","Court must find detriment to deny relocation","Applies to parents with sole or primary physical custody"]', '[{"section":"Holding","description":"Custodial parent presumptive relocation right"},{"section":"Test","description":"Would relocation cause detriment to child?"}]', '["move_away_motion","custody_order","court_order"]', '["california-family-law-expansion-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));

